//! 统一 MCP 响应格式
//!
//! 所有 MCP 工具返回此信封结构，确保 Agent 端解析一致。
//!
//! 结构示例:
//! ```json
//! {
//!   "request_id": "uuid",
//!   "status": "success|partial|error",
//!   "warnings": [],
//!   "data": { ... },
//!   "meta": {
//!     "took_ms": 42,
//!     "total_results": 150,
//!     "returned_results": 50,
//!     "next_page_token": null,
//!     "index_staleness_ms": 120000
//!   }
//! }
//! ```

use serde::{Deserialize, Serialize};
use uuid::Uuid;

/// 统一 MCP 响应信封
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct McpResponse<T: Serialize> {
    /// 请求唯一标识
    pub request_id: String,
    /// 响应状态
    pub status: ResponseStatus,
    /// 警告信息（如部分索引数据过期）
    #[serde(skip_serializing_if = "Vec::is_empty")]
    pub warnings: Vec<String>,
    /// 实际数据载荷
    pub data: Option<T>,
    /// 元信息
    pub meta: ResponseMeta,
}

/// 响应状态枚举
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "lowercase")]
pub enum ResponseStatus {
    /// 完全成功
    Success,
    /// 部分成功（含警告）
    Partial,
    /// 错误
    Error,
}

/// 响应元信息
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ResponseMeta {
    /// 查询耗时（毫秒）
    pub took_ms: u64,
    /// 总结果数
    pub total_results: usize,
    /// 本次返回结果数
    pub returned_results: usize,
    /// 分页游标（下一页使用）
    pub next_page_token: Option<String>,
    /// 索引陈旧度（毫秒），自上次索引更新以来经过的时间
    pub index_staleness_ms: Option<u64>,
}

impl<T: Serialize> McpResponse<T> {
    /// 创建成功响应
    pub fn success(data: T, total: usize, returned: usize, took_ms: u64) -> Self {
        Self {
            request_id: Uuid::new_v4().to_string(),
            status: ResponseStatus::Success,
            warnings: vec![],
            data: Some(data),
            meta: ResponseMeta {
                took_ms,
                total_results: total,
                returned_results: returned,
                next_page_token: None,
                index_staleness_ms: None,
            },
        }
    }

    /// 创建错误响应
    pub fn error(message: &str) -> Self {
        Self {
            request_id: Uuid::new_v4().to_string(),
            status: ResponseStatus::Error,
            warnings: vec![message.to_string()],
            data: None,
            meta: ResponseMeta {
                took_ms: 0,
                total_results: 0,
                returned_results: 0,
                next_page_token: None,
                index_staleness_ms: None,
            },
        }
    }

    /// 创建部分成功响应（含警告）
    pub fn partial(data: T, total: usize, returned: usize, took_ms: u64, warnings: Vec<String>) -> Self {
        Self {
            request_id: Uuid::new_v4().to_string(),
            status: ResponseStatus::Partial,
            warnings,
            data: Some(data),
            meta: ResponseMeta {
                took_ms,
                total_results: total,
                returned_results: returned,
                next_page_token: None,
                index_staleness_ms: None,
            },
        }
    }

    /// 添加警告信息
    pub fn with_warning(mut self, warning: String) -> Self {
        self.warnings.push(warning);
        self.status = ResponseStatus::Partial;
        self
    }

    /// 设置分页游标
    pub fn with_page_token(mut self, token: String) -> Self {
        self.meta.next_page_token = Some(token);
        self
    }

    /// 设置索引陈旧度
    pub fn with_staleness(mut self, staleness_ms: u64) -> Self {
        self.meta.index_staleness_ms = Some(staleness_ms);
        self
    }
}

/// 分页游标（Base64 编码的偏移信息）
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PageToken {
    /// 查询哈希（确保游标属于同一查询）
    pub query_hash: String,
    /// 偏移量
    pub offset: usize,
}

