### 2. crates/parser/src/import_resolver.rs — ImportResolver trait

```rust
//! 导入解析器
//!
//! 将调用点的被调用者名称解析为稳定的符号 ID。
//! 每种语言实现自己的导入解析策略。

use std::collections::HashMap;
use std::path::{Path, PathBuf};

use codeconnect_core::error::CodeConnectError;

/// 解析结果
#[derive(Debug, Clone)]
pub struct ResolutionResult {
    /// 候选目标符号 ID 列表
    pub candidates: Vec<CandidateTarget>,
    /// 解析策略（同文件、同包、外部包等）
    pub strategy: String,
}

/// 候选目标
#[derive(Debug, Clone)]
pub struct CandidateTarget {
    /// 目标符号稳定 ID
    pub symbol_id: String,
    /// 置信度 0.0-1.0
    pub confidence: f64,
    /// 解析路径（如 "import:std::io::Read → resolved"）
    pub resolution_path: String,
}

/// 导入解析器 trait
///
/// 每种语言的解析器实现此 trait，提供跨文件调用目标解析能力。
pub trait ImportResolver: Send + Sync {
    /// 返回解析器支持的语言名
    fn language(&self) -> &'static str;

    /// 解析调用目标
    ///
    /// * `callee_name` - 被调用者名称（简单名或部分限定名）
    /// * `caller_file` - 调用者文件路径
    /// * `imports` - 调用者文件内的所有导入映射（文件名 → 已解析的符号 ID 列表）
    fn resolve(
        &self,
        callee_name: &str,
        caller_file: &Path,
        imports: &HashMap<String, Vec<String>>,
    ) -> Result<ResolutionResult, CodeConnectError>;

    /// 尝试定位一个外部模块的文件路径
    ///
