96	        let mut results = Vec::new();
97	
98	        let query = match Query::new(&tree_sitter_rust::LANGUAGE.into(), &queries.symbols) {
99	            Ok(q) => q,
100	            Err(_) => return results,
101	        };
102	
103	        let mut cursor = QueryCursor::new();
104	        let matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
105	
106	        for m in matches {
107	            let m = match m {
108	                Ok(m) => m,
109	                Err(_) => continue,
110	            };
111	
112	            let mut name = String::new();
113	            let mut parent = String::new();
114	            let mut kind = SymbolKind::Unknown("unknown".to_string());
115	            let mut location = SourceLocation {
116	                file_path: file_path_str.clone(),
117	                line: 0,
118	                column: 0,
119	                end_line: 0,
120	                end_column: 0,
121	            };
122	
123	            for capture in m.captures {
124	                let node = capture.node;
125	                let capture_name = query.capture_names()[capture.index as usize];
126	
127	                match capture_name {
128	                    "symbol.name" => {
129	                        name = self.node_text(node, source).to_string();
130	                    }
131	                    "symbol.function" => {
132	                        kind = SymbolKind::Function;
