134	                    }
135	                    "symbol.method" => {
136	                        kind = SymbolKind::Method;
137	                        location = self.node_to_location(source, node);
138	                    }
139	                    "symbol.struct" => {
140	                        kind = SymbolKind::Struct;
141	                        location = self.node_to_location(source, node);
142	                    }
143	                    "symbol.trait" => {
144	                        kind = SymbolKind::Trait;
145	                        location = self.node_to_location(source, node);
146	                    }
147	                    "symbol.enum" => {
148	                        kind = SymbolKind::Enum;
149	                        location = self.node_to_location(source, node);
150	                    }
151	                    "symbol.type_alias" => {
152	                        kind = SymbolKind::TypeAlias;
153	                        location = self.node_to_location(source, node);
154	                    }
155	                    "symbol.macro" => {
156	                        kind = SymbolKind::Macro;
157	                        location = self.node_to_location(source, node);
158	                    }
159	                    "symbol.module" => {
160	                        kind = SymbolKind::Module;
161	                        location = self.node_to_location(source, node);
162	                    }
