1	//! 全量索引引擎
2	//!
3	//! 遍历项目目录，用 rayon 并行解析所有源文件，
4	//! 提取符号、调用和导入信息，批量写入 tantivy 和 sled。
5	//!
6	//! 流程：
7	//! 1. `ignore` crate 遍历目录（自动 .gitignore 过滤）
8	//! 2. 按文件扩展名匹配解析器
9	//! 3. `rayon` 并行解析
10	//! 4. `crossbeam` channel 收集结果
11	//! 5. 批量写入 tantivy + sled
12	
13	use std::collections::HashMap;
14	use std::path::{Path, PathBuf};
15	use std::sync::Arc;
16	use std::time::SystemTime;
17	
18	use crossbeam::channel;
19	use rayon::prelude::*;
20	
21	use codeconnect_core::error::CodeConnectError;
22	use codeconnect_core::types::{FileMeta, SymbolKind};
23	use codeconnect_parser::factory::ParserRegistry;
24	use ignore::WalkBuilder;
25	
26	use crate::sled_store::SledStore;
27	use crate::tantivy_index::{TantivyIndex, CURRENT_SCHEMA_VERSION};
28	
29	// ============================================================================
30	// 统计结构
31	// ============================================================================
32	
33	/// 索引统计信息
34	///
35	/// 记录一次全量索引运行的整体结果，包括扫描文件数、
36	/// 解析成功率、提取的符号/调用/导入数量等。
37	#[derive(Debug, Clone)]
38	pub struct IndexStats {
39	    /// 扫描的文件总数
40	    pub files_scanned: u64,
41	    /// 成功解析的文件数
42	    pub files_parsed: u64,
43	    /// 提取的符号总数
44	    pub symbols_found: u64,
45	    /// 发现的调用点数
46	    pub calls_found: u64,
47	    /// 发现的导入数
48	    pub imports_found: u64,
49	    /// 解析失败的文件列表（路径 + 错误信息）
50	    pub failed_files: Vec<String>,
51	}
52	
53	/// 单个文件的索引统计（内部用）
54	#[derive(Debug, Clone, Default)]
55	struct FileIndexStats {
56	    symbols: u64,
57	    calls: u64,
58	    imports: u64,
59	}
60	
61	impl FileIndexStats {
62	    /// 合并多个文件的统计数据
63	    fn merge(stats: &[Self]) -> Self {
64	        let mut merged = Self::default();
65	        for s in stats {
66	            merged.symbols += s.symbols;
67	            merged.calls += s.calls;
68	            merged.imports += s.imports;
69	        }
70	        merged
71	    }
72	}
73	
74	// ============================================================================
75	// 解析结果 — channel 传输的数据包
76	// ============================================================================
77	
78	/// 单个文件的解析结果
79	struct ParsedFile {
80	    /// 文件相对路径字符串
81	    relative_path: String,
82	    /// 内容 blake3 哈希的十六进制字符串
83	    content_hash: String,
84	    /// 编程语言名称
85	    language: &'static str,
86	    /// 提取的符号列表
87	    symbols: Vec<codeconnect_core::types::Symbol>,
88	    /// 提取的调用点列表
89	    calls: Vec<codeconnect_core::types::CallSite>,
90	    /// 提取的导入列表
91	    imports: Vec<codeconnect_core::types::Import>,
92	    /// 统计计数
93	    stats: FileIndexStats,
94	}
95	
96	/// 解析失败的文件信息
97	struct ParseFailure {
98	    /// 文件路径
99	    file_path: PathBuf,
100	    /// 错误信息
101	    error: String,
102	}
103	
104	// ============================================================================
105	// 全量索引引擎
106	// ============================================================================
107	
108	/// 全量索引引擎
109	///
110	/// 负责遍历项目目录中的所有源文件，并行解析并提取符号信息，
111	/// 然后将结果批量写入 tantivy 全文索引和 sled 键值存储。
112	///
113	/// # 使用示例
114	///
115	/// ```ignore
116	/// let mut registry = Arc::new(ParserRegistry::new());
117	/// // ... 注册解析器 ...
118	/// let tantivy = TantivyIndex::open_or_create(index_dir)?;
119	/// let sled = SledStore::open(sled_dir)?;
120	/// let indexer = FullIndexer::new(project_root, tantivy, sled, registry);
121	/// let stats = indexer.run()?;
122	/// println!("索引完成: {:?}", stats);
123	/// ```
124	pub struct FullIndexer {
125	    /// 项目根目录
126	    project_root: PathBuf,
127	    /// tantivy 全文搜索索引
128	    tantivy: TantivyIndex,
129	    /// sled 键值存储
130	    sled: SledStore,
131	    /// 解析器注册表
132	    parser_registry: Arc<ParserRegistry>,
133	}
134	
135	impl FullIndexer {
136	    /// 创建全量索引器
137	    ///
138	    /// # 参数
139	    /// - `project_root` — 项目根目录路径
140	    /// - `tantivy` — 已初始化的 tantivy 索引实例
141	    /// - `sled` — 已打开的 sled 存储实例
142	    /// - `parser_registry` — 已注册所有语言解析器的注册表
143	    pub fn new(
144	        project_root: &Path,
145	        tantivy: TantivyIndex,
146	        sled: SledStore,
147	        parser_registry: Arc<ParserRegistry>,
148	    ) -> Self {
149	        Self {
150	            project_root: project_root.to_path_buf(),
151	            tantivy,
152	            sled,
153	            parser_registry,
154	        }
155	    }
156	
157	    /// 运行全量索引
158	    ///
159	    /// 这是索引引擎的主入口，执行完整的索引流程：
160	    /// 文件收集 → 并行解析 → 批量写入 → 提交刷盘
161	    ///
162	    /// # 返回
163	    /// 返回 [`IndexStats`] 包含详细的统计信息。
164	    pub fn run(&self) -> Result<IndexStats, CodeConnectError> {
165	        // ====================================================================
166	        // 第一步：收集需要解析的文件列表
167	        // ====================================================================
168	        let files = self.collect_files()?;
169	        let files_scanned = files.len() as u64;
170	
171	        tracing::info!("扫描完成，共发现 {} 个源文件", files_scanned);
172	
173	        if files.is_empty() {
174	            return Ok(IndexStats {
175	                files_scanned: 0,
176	                files_parsed: 0,
177	                symbols_found: 0,
178	                calls_found: 0,
179	                imports_found: 0,
180	                failed_files: Vec::new(),
181	            });
182	        }
183	
184	        // ====================================================================
185	        // 第二步：使用 rayon 并行解析所有文件
186	        // 通过 crossbeam channel 收集解析结果和失败信息
187	        // ====================================================================
188	        let (success_tx, success_rx) = channel::unbounded::<ParsedFile>();
189	        let (failure_tx, failure_rx) = channel::unbounded::<ParseFailure>();
190	
191	        let project_root = Arc::new(self.project_root.clone());
192	        let parser_registry = Arc::clone(&self.parser_registry);
193	
194	        files.par_iter().for_each(|file_path| {
195	            match parse_single_file(file_path, &parser_registry, &project_root) {
196	                Ok(parsed) => {
197	                    let _ = success_tx.send(parsed);
198	                }
199	                Err(error) => {
200	                    let _ = failure_tx.send(ParseFailure {
201	                        file_path: file_path.clone(),
202	                        error,
203	                    });
204	                }
205	            }
206	        });
207	
208	        // 关闭发送端，以便接收端的迭代可以自然结束
209	        drop(success_tx);
210	        drop(failure_tx);
211	
212	        // ====================================================================
213	        // 第三步：收集结果并批量写入存储
214	        // ====================================================================
215	        let mut files_parsed: u64 = 0;
216	        let mut symbols_found: u64 = 0;
217	        let mut calls_found: u64 = 0;
218	        let mut imports_found: u64 = 0;
219	        let mut failed_files: Vec<String> = Vec::new();
220	
221	        // 按文件收集符号 ID 列表，用于写文件→符号映射
222	        let mut file_symbol_map: HashMap<String, FileIndexStats> = HashMap::new();
223	
224	        for parsed in success_rx {
225	            let relative_path = parsed.relative_path.clone();
226	            let stats = parsed.stats;
227	
228	            // 写入 sled 和 tantivy
229	            self.write_parsed_file(&parsed)?;
230	
231	            files_parsed += 1;
232	            symbols_found += stats.symbols;
233	            calls_found += stats.calls;
234	            imports_found += stats.imports;
235	
236	            file_symbol_map.insert(relative_path, stats);
237	        }
238	
239	        // 收集解析失败的文件
240	        for failure in failure_rx {
241	            failed_files.push(format!(
242	                "{}: {}",
243	                failure.file_path.display(),
244	                failure.error
245	            ));
246	        }
247	
248	        // ====================================================================
249	        // 第四步：提交 tantivy 写入
250	        // ====================================================================
251	        self.tantivy.commit()?;
252	
253	        // ====================================================================
254	        // 第五步：写入 Schema 版本并刷盘
255	        // ====================================================================
256	        self.sled.put_schema_version(CURRENT_SCHEMA_VERSION)?;
257	        self.sled.flush()?;
258	
259	        tracing::info!(
260	            "全量索引完成: {} 成功 / {} 失败, {} 符号, {} 调用, {} 导入",
261	            files_parsed,
262	            failed_files.len(),
263	            symbols_found,
264	            calls_found,
265	            imports_found
266	        );
267	
268	        Ok(IndexStats {
269	            files_scanned,
270	            files_parsed,
271	            symbols_found,
272	            calls_found,
273	            imports_found,
274	            failed_files,
275	        })
276	    }
277	
278	    /// 收集项目目录下的所有源文件
279	    ///
280	    /// 使用 `ignore::WalkBuilder` 遍历目录树，自动应用
281	    /// `.gitignore` 规则过滤，仅收集支持的编程语言源文件。
282	    fn collect_files(&self) -> Result<Vec<PathBuf>, CodeConnectError> {
283	        let mut files = Vec::new();
284	
285	        let walker = WalkBuilder::new(&self.project_root)
286	            .standard_filters(true) // 自动 .gitignore 与常见忽略规则
287	            .hidden(false) // 不跳过隐藏文件（某些配置目录需要处理）
288	            .build();
289	
290	        for entry in walker {
291	            let entry = entry
292	                .map_err(|e| CodeConnectError::Index(format!("目录遍历失败: {}", e)))?;
293	
294	            // 只处理普通文件
295	            if !entry.file_type().map_or(false, |ft| ft.is_file()) {
296	                continue;
297	            }
298	
299	            let path = entry.path();
300	
301	            // 按扩展名过滤支持的编程语言
302	            if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
303	                let supported = matches!(
304	                    ext,
305	                    "rs" | "ts" | "tsx" | "js" | "jsx" | "mjs" | "cjs" | "java" | "cs"
306	                );
307	                if supported {
308	                    files.push(path.to_path_buf());
309	                }
310	            }
311	        }
312	
313	        // 按路径排序以保证索引顺序稳定
314	        files.sort();
315	
316	        Ok(files)
317	    }
318	
319	    /// 将单个文件的解析结果写入存储
320	    ///
321	    /// 包括：文件元信息、符号定义、文件指纹、文件→符号映射，
322	    /// 以及将每个符号写入 tantivy 全文索引。
323	    fn write_parsed_file(&self, parsed: &ParsedFile) -> Result<(), CodeConnectError> {
324	        let file_path_str = &parsed.relative_path;
325	
326	        // ---- 写入文件元信息 ----
327	        let file_meta = FileMeta {
328	            file_path: file_path_str.clone(),
329	            language: parsed.language.to_string(),
330	            content_hash: parsed.content_hash.clone(),
331	            symbol_count: parsed.symbols.len() as u64,
332	            indexed_at: SystemTime::now()
333	                .duration_since(SystemTime::UNIX_EPOCH)
334	                .unwrap_or_default()
335	                .as_secs() as i64,
336	        };
337	
338	        let meta_bytes = serde_json::to_vec(&file_meta)
339	            .map_err(|e| CodeConnectError::Index(format!("序列化文件元信息失败: {}", e)))?;
340	        self.sled.put_file_meta(file_path_str, &meta_bytes)?;
341	
342	        // ---- 收集文件内所有符号 ID ----
343	        let mut file_symbol_ids: Vec<String> = Vec::with_capacity(parsed.symbols.len());
344	
345	        // ---- 写入每个符号定义 ----
346	        for symbol in &parsed.symbols {
347	            file_symbol_ids.push(symbol.id.clone());
348	
349	            let sym_bytes = serde_json::to_vec(symbol)
350	                .map_err(|e| CodeConnectError::Index(format!("序列化符号失败: {}", e)))?;
351	            self.sled.put_symbol(&symbol.id, &sym_bytes)?;
352	
353	            // ---- 写入 tantivy 全文索引 ----
354	            Self::add_symbol_to_tantivy(&self.tantivy, symbol, parsed, file_path_str)?;
355	        }
356	
357	        // ---- 写入文件→符号映射 ----
358	        let file_symbol_bytes = serde_json::to_vec(&file_symbol_ids)
359	            .map_err(|e| CodeConnectError::Index(format!("序列化文件符号映射失败: {}", e)))?;
360	        self.sled
361	            .put_file_symbols(file_path_str, &file_symbol_bytes)?;
362	
363	        // ---- 写入文件指纹 ----
364	        self.sled
365	            .put_fingerprint(file_path_str, parsed.content_hash.as_bytes())?;
366	
367	        Ok(())
368	    }
369	
370	    /// 将单个符号添加到 tantivy 全文索引
371	    fn add_symbol_to_tantivy(
372	        tantivy: &TantivyIndex,
373	        symbol: &codeconnect_core::types::Symbol,
374	        parsed: &ParsedFile,
375	        file_path_str: &str,
376	    ) -> Result<(), CodeConnectError> {
377	        // 将 SymbolKind 枚举映射为字符串
378	        let kind_str = match &symbol.kind {
379	            SymbolKind::Function => "function",
380	            SymbolKind::Method => "method",
381	            SymbolKind::Class => "class",
382	            SymbolKind::Interface => "interface",
383	            SymbolKind::Struct => "struct",
384	            SymbolKind::Enum => "enum",
385	            SymbolKind::Trait => "trait",
386	            SymbolKind::TypeAlias => "type_alias",
387	            SymbolKind::Variable => "variable",
388	            SymbolKind::Field => "field",
389	            SymbolKind::Module => "module",
390	            SymbolKind::Macro => "macro",
391	            SymbolKind::Parameter => "parameter",
392	            SymbolKind::Unknown(_) => "unknown",
393	        };
394	
395	        // 修饰符列表以逗号+空格拼接
396	        let modifiers_str = symbol.modifiers.join(", ");
397	
398	        tantivy.add_symbol(
399	            &symbol.id,
400	            &symbol.name,
401	            kind_str,
402	            parsed.language,
403	            file_path_str,
404	            symbol.signature.as_deref().unwrap_or(""),
405	            symbol.doc_comment.as_deref().unwrap_or(""),
406	            "", // definition — 暂不在解析器中提取
407	            "", // body_text — 暂不在解析器中提取
408	            symbol.parent_id.as_deref().unwrap_or(""),
409	            &modifiers_str,
410	            symbol.complexity.unwrap_or(0),
411	            "", // ast_hash — 暂不在此阶段计算
412	            symbol.is_exported,
413	        )
414	    }
415	}
416	
417	// ============================================================================
418	// 并行解析辅助函数
419	// ============================================================================
420	
421	/// 解析单个文件并提取所有结构化信息
422	///
423	/// 此函数设计为可在 rayon 并行迭代中调用，无外部可变依赖。
424	/// 所有数据通过返回值传递，由主线程统一写入存储。
425	fn parse_single_file(
426	    file_path: &Path,
427	    parser_registry: &Arc<ParserRegistry>,
428	    project_root: &Path,
429	) -> Result<ParsedFile, String> {
430	    // 查找对应的解析器
431	    let parser = parser_registry
432	        .get_for_file(file_path)
433	        .ok_or_else(|| format!("不支持的文件类型: {}", file_path.display()))?;
434	
