1	//! 增量索引器
2	//!
3	//! 响应文件变更事件，对比文件指纹，仅重新解析变更的文件。
4	//!
5	//! # 工作流程
6	//!
7	//! 1. **接收变更** — 从 [`FileWatcher`](codeconnect_watcher::watcher::FileWatcher) 接收文件变更批次
8	//! 2. **指纹对比** — 与 sled 中存储的文件指纹比较，跳过内容未变化的文件
9	//! 3. **删除旧数据** — 从 sled 和 tantivy 中移除变更文件的旧符号
10	//! 4. **重新解析** — 调用解析器重新解析变更的源文件
11	//! 5. **写入新索引** — 将新的符号、调用、导入信息写入 sled 和 tantivy
12	//!
13	//! # 使用
14	//!
15	//! ```ignore
16	//! let indexer = IncrementalIndexer::new(project_root, sled, tantivy, parser_registry)?;
17	//! indexer.start_watching(excludes).await?;
18	//! ```
19	
20	use std::collections::HashSet;
21	use std::path::{Path, PathBuf};
22	use std::sync::Arc;
23	
24	use codeconnect_core::error::CodeConnectError;
25	use codeconnect_core::types::{FileMeta, SymbolKind};
26	use crate::sled_store::SledStore;
27	use crate::tantivy_index::TantivyIndex;
28	use codeconnect_parser::factory::ParserRegistry;
29	use codeconnect_watcher::watcher::FileWatcher;
30	use tokio::sync::mpsc;
31	
32	/// 增量索引器
33	///
34	/// 封装文件监控和增量索引更新逻辑，提供统一的启动入口。
35	///
36	/// 持有所有索引和解析所需的共享资源：项目根目录、
37	/// sled 存储、tantivy 索引、解析器注册表。
38	pub struct IncrementalIndexer {
39	    /// 项目根目录
40	    project_root: PathBuf,
41	    /// sled K/V 存储
42	    sled: Arc<SledStore>,
43	    /// tantivy 全文搜索索引
44	    tantivy: Arc<TantivyIndex>,
45	    /// 解析器注册表
46	    parser_registry: Arc<ParserRegistry>,
47	}
48	
49	impl IncrementalIndexer {
50	    /// 创建增量索引器
51	    ///
52	    /// # 参数
53	    ///
54	    /// - `project_root` — 项目根目录路径
55	    /// - `sled` — 已打开的 sled 存储实例
56	    /// - `tantivy` — 已初始化的 tantivy 索引实例
57	    /// - `parser_registry` — 已注册所有语言解析器的注册表
58	    pub fn new(
59	        project_root: &Path,
60	        sled: Arc<SledStore>,
61	        tantivy: Arc<TantivyIndex>,
62	        parser_registry: Arc<ParserRegistry>,
63	    ) -> Self {
64	        Self {
65	            project_root: project_root.to_path_buf(),
66	            sled,
67	            tantivy,
68	            parser_registry,
69	        }
70	    }
71	
72	    /// 启动文件监控和增量索引
73	    ///
74	    /// 创建 [`FileWatcher`] 并启动异步监控循环。
75	    /// 接收到的文件变更批次经过去重和指纹对比后，
76	    /// 仅对真正变化的文件执行增量重索引。
77	    ///
78	    /// # 参数
79	    ///
80	    /// - `excludes` — 文件排除模式列表
81	    ///
82	    /// # 返回
83	    ///
84	    /// 此方法在文件监控持续运行期间不会返回，返回 `Ok(())`
85	    /// 表示监控停止。
86	    pub async fn start_watching(
87	        &self,
88	        excludes: Vec<String>,
89	    ) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
90	        let (tx, mut rx) = mpsc::unbounded_channel::<Vec<PathBuf>>();
91	
92	        let watcher = FileWatcher::new(&self.project_root, excludes);
93	
94	        // 在后台任务中运行文件监控
95	        let watch_handle = tokio::spawn(async move {
96	            if let Err(e) = watcher.start(tx).await {
97	                tracing::error!("文件监控启动失败: {}", e);
98	            }
99	        });
100	
101	        tracing::info!("增量索引器已启动，正在监控文件变更...");
102	
103	        // 处理文件变更事件
104	        while let Some(changed_files) = rx.recv().await {
105	            if let Err(e) = self.reindex_files(&changed_files) {
106	                tracing::error!("增量索引失败: {}", e);
107	            }
108	        }
109	
110	        // 监控通道关闭，等待后台任务结束
111	        let _ = watch_handle.await;
112	
113	        tracing::info!("增量索引器已停止");
114	        Ok(())
115	    }
116	
117	    /// 对指定文件列表执行增量重索引
118	    ///
119	    /// 这是增量索引的核心方法，执行以下操作：
120	    ///
121	    /// 1. **去重** — 移除路径列表中的重复项
122	    /// 2. **指纹对比** — 计算文件内容的 blake3 哈希，与 sled 中存储的指纹比较
123	    /// 3. **删除旧符号** — 从 sled 和 tantivy 中移除变更文件的旧数据
124	    /// 4. **重新解析** — 调用解析器重新提取符号、调用和导入
125	    /// 5. **写入新索引** — 将新数据写入 sled 和 tantivy
126	    ///
127	    /// # 参数
128	    ///
129	    /// - `file_paths` — 变更的文件路径列表
130	    pub fn reindex_files(&self, file_paths: &[PathBuf]) -> Result<(), CodeConnectError> {
131	        // ---- 第一步：去重 ----
132	        let unique_paths: HashSet<&Path> = file_paths.iter().map(|p| p.as_path()).collect();
133	        let unique_paths: Vec<&Path> = unique_paths.into_iter().collect();
134	
135	        if unique_paths.is_empty() {
136	            return Ok(());
137	        }
138	
139	        tracing::info!("增量索引: 处理 {} 个变更文件", unique_paths.len());
140	
141	        let mut reindexed_count: u64 = 0;
142	        let mut skipped_count: u64 = 0;
143	
144	        for file_path in &unique_paths {
145	            // ---- 计算相对于项目根目录的路径 ----
146	            let relative_path = file_path
147	                .strip_prefix(&self.project_root)
148	                .unwrap_or(file_path)
149	                .to_string_lossy()
150	                .to_string();
151	
152	            // ---- 第二步：读取内容并计算指纹 ----
153	            let source = match std::fs::read_to_string(file_path) {
154	                Ok(s) => s,
155	                Err(e) => {
156	                    // 文件可能已被删除 — 清理索引中的旧数据
157	                    tracing::debug!("无法读取文件 {}: {}，从索引中移除", file_path.display(), e);
158	                    self.remove_file_from_index(&relative_path)?;
159	                    reindexed_count += 1;
160	                    continue;
161	                }
162	            };
163	
164	            let new_hash = blake3::hash(source.as_bytes()).to_hex().to_string();
165	
166	            // 检查是否内容真正变化
167	            if let Ok(Some(old_hash_bytes)) = self.sled.get_fingerprint(&relative_path) {
168	                let old_hash = String::from_utf8_lossy(&old_hash_bytes).to_string();
169	                if old_hash == new_hash {
170	                    tracing::debug!("文件 {} 内容未变化，跳过", relative_path);
171	                    skipped_count += 1;
172	                    continue;
173	                }
174	            }
175	
176	            // ---- 第三步：删除旧数据 ----
177	            self.remove_file_from_index(&relative_path)?;
178	
179	            // ---- 第四步：查找并调用解析器 ----
180	            let parser = match self.parser_registry.get_for_file(file_path) {
181	                Some(p) => p,
182	                None => {
183	                    tracing::debug!("不支持的文件类型: {}", file_path.display());
184	                    continue;
185	                }
186	            };
187	
188	            let language = parser.language();
189	
190	            // ---- 第五步：解析源文件 ----
191	            let tree = match parser.parse(&source) {
192	                Ok(t) => t,
193	                Err(e) => {
194	                    tracing::warn!("解析失败 {}: {}", file_path.display(), e);
195	                    continue;
196	                }
197	            };
198	
199	            let symbols = parser.extract_symbols(&tree, &source, file_path);
200	            let _calls = parser.extract_calls(&tree, &source, file_path);
201	            let _imports = parser.extract_imports(&tree, &source, file_path);
202	
203	            // ---- 第六步：写入新索引数据 ----
204	            self.write_file_index(&relative_path, &new_hash, language, &symbols)?;
205	
206	            tracing::debug!(
207	                "重索引完成: {} ({} 个符号)",
208	                relative_path,
209	                symbols.len()
210	            );
211	            reindexed_count += 1;
212	        }
213	
214	        // 提交 tantivy 并刷写 sled
215	        // 注意: 由于我们持有 Arc<TantivyIndex> 而非 &mut，这里的 commit 是有限制的
216	        // 在主流程中由 FullIndexer 或外部调用者负责 commit
217	
218	        tracing::info!(
219	            "增量索引完成: {} 重索引 / {} 跳过",
220	            reindexed_count,
221	            skipped_count
222	        );
223	
224	        Ok(())
225	    }
226	
227	    /// 从索引中移除文件的所有关联数据
228	    ///
229	    /// 包括：文件元信息、符号定义、文件→符号映射、文件指纹。
230	    /// 通常在文件被删除或即将重索引前调用。
231	    fn remove_file_from_index(&self, relative_path: &str) -> Result<(), CodeConnectError> {
232	        // 获取文件内所有符号 ID
233	        if let Ok(Some(bytes)) = self.sled.get_file_symbols(relative_path) {
234	            let symbol_ids: Vec<String> =
235	                serde_json::from_slice(&bytes).unwrap_or_default();
236	
237	            // 删除每个符号的定义
238	            for sid in &symbol_ids {
239	                let _ = self.sled.delete_symbol(sid);
240	            }
241	        }
242	
243	        // 删除文件→符号映射
244	        let _ = self.sled.remove_file_symbols(relative_path);
245	
246	        // 删除文件元信息
247	        let _ = self.sled.remove_file_meta(relative_path);
248	

