107	    Ok(())
108	}

1	//! 离线分析子命令
2	//!
3	//! 执行代码质量分析：圈复杂度、死代码检测、架构规则验证等。
4	
5	use std::path::Path;
6	
7	use codeconnect_core::types::Symbol;
8	use codeconnect_graph::call_graph::CallGraph;
9	use codeconnect_graph::metrics::MetricCalculator;
10	use codeconnect_graph::type_hierarchy::TypeHierarchy;
11	use codeconnect_index::sled_store::SledStore;
12	
13	/// 执行离线分析
14	///
15	/// # 参数
16	///
17	/// - `project_root` — 项目根目录
18	/// - `data_dir` — 索引数据目录
19	/// - `analyze_type` — 分析类型（metrics、deadcode、complexity、all）
20	pub async fn run(
21	    project_root: &Path,
22	    data_dir: &Path,
23	    analyze_type: &str,
24	) -> Result<(), Box<dyn std::error::Error>> {
25	    let _ = project_root;
26	
27	    let sled_dir = data_dir.join("sled");
28	    let sled = SledStore::open(&sled_dir)
29	        .map_err(|e| format!("无法打开 sled 存储: {}", e))?;
30	
31	    // 收集所有符号
32	    let mut all_symbols: Vec<Symbol> = Vec::new();
33	    let prefix = "symbols:";
34	    for item in sled.scan_prefix(prefix.as_bytes()) {
35	        if let Ok((_key, value)) = item {
36	            if let Ok(sym) = serde_json::from_slice::<Symbol>(&value) {
37	                all_symbols.push(sym);
38	            }
39	        }
40	    }
41	
42	    if all_symbols.is_empty() {
43	        println!("索引中没有符号数据，请先运行 `codeconnect index`");
44	        return Ok(());
45	    }
46	
47	    println!("符号总数: {}", all_symbols.len());
48	    println!();
49	
50	    // 构建调用图
51	    let call_graph = CallGraph::build_from_sled(&sled)
52	        .map_err(|e| format!("构建调用图失败: {}", e))?;
53	
54	    let type_hierarchy = TypeHierarchy::new();
55	
56	    match analyze_type {
57	        "complexity" | "metrics" | "all" => {
58	            // 计算圈复杂度排名
59	            println!("═══════════════════════════════════════════");
60	            println!("  圈复杂度分析（Top 10）");
61	            println!("═══════════════════════════════════════════");
62	
63	            let metrics = MetricCalculator::compute_all(&all_symbols, &call_graph, &type_hierarchy);
64	
65	            let mut sorted: Vec<_> = metrics.iter().collect();
66	            sorted.sort_by(|a, b| b.cyclomatic_complexity.cmp(&a.cyclomatic_complexity));
67	
68	            for (i, m) in sorted.iter().take(10).enumerate() {
69	                let marker = if m.cyclomatic_complexity > 30 {
70	                    " 🔴"
71	                } else if m.cyclomatic_complexity > 15 {
72	                    " 🟡"
73	                } else {
74	                    ""
75	                };
76	                println!(
77	                    "  {}. {} — 复杂度: {}{} (入:{} / 出:{})",
78	                    i + 1,
79	                    m.name,
80	                    m.cyclomatic_complexity,
81	                    marker,
82	                    m.fan_in,
83	                    m.fan_out,
84	                );
85	            }
86	
87	            // 全局统计
88	            let total_complexity: u64 = metrics.iter().map(|m| m.cyclomatic_complexity).sum();
89	            let avg_complexity = if metrics.is_empty() {
90	                0.0
91	            } else {
92	                total_complexity as f64 / metrics.len() as f64
93	            };
94	            let high_complexity = metrics
95	                .iter()
96	                .filter(|m| m.cyclomatic_complexity > 15)
97	                .count();
98	            let very_high = metrics
99	                .iter()
100	                .filter(|m| m.cyclomatic_complexity > 30)
101	                .count();
102	
103	            println!();
104	            println!("  全局统计:");
105	            println!("    总符号数:     {}", metrics.len());
106	            println!("    平均复杂度:   {:.1}", avg_complexity);
107	            println!("    高复杂度(>15): {}", high_complexity);
108	            println!("    极高复杂度(>30): {}", very_high);
109	            println!();
110	        }
111	
112	        _ => {}
113	    }
114	
115	    // 死代码检测（第二个阶段，在 complexity 结果之后按条件运行）
116	    if analyze_type == "deadcode" || analyze_type == "all" {
117	            // 死代码检测
118	            println!("═══════════════════════════════════════════");
119	            println!("  死代码检测");
120	            println!("═══════════════════════════════════════════");
121	
122	            let all_names: Vec<String> = all_symbols.iter().map(|s| s.name.clone()).collect();
123	            let entries = vec!["main".to_string()];
124	
125	            let dead = MetricCalculator::detect_dead_code(&all_names, &call_graph, &entries);
126	
127	            if dead.is_empty() {
128	                println!("  未检测到死代码");
129	            } else {
130	                for d in &dead {
131	                    let confidence_str = if d.confidence >= 0.8 {
132	                        "高"
133	                    } else if d.confidence >= 0.5 {
134	                        "中"
135	                    } else {
136	                        "低"
137	                    };
138	                    println!(
139	                        "  {} — 置信度: {} ({:.0}%)",
140	                        d.name,
141	                        confidence_str,
142	                        d.confidence * 100.0
143	                    );
144	                    println!("    {}", d.reason);
145	                }
146	                println!();
147	                println!("  共 {} 个可疑死代码条目", dead.len());
148	            }
149	            println!();
150	    }
151	
152	    Ok(())
153	}
